// App Lock: gates the whole app behind the device's own biometric/PIN
// authenticator via WebAuthn (Face ID, Touch ID, fingerprint, Windows
// Hello, or device PIN as OS-level fallback). This is a pure client-side
// gate, not a remote-auth system -- there's no server to verify a
// signature against, so a successful navigator.credentials.get() ceremony
// (the browser itself confirming the platform authenticator) is the proof.
// The private key is generated by and never leaves the device's secure
// enclave/TPM either way, so this adds real device-level security even
// without a verifying server.

const RP_NAME = 'Life OS';

function randomBytes(len) {
  return crypto.getRandomValues(new Uint8Array(len));
}

function bufToBase64url(buf) {
  let str = '';
  for (const b of new Uint8Array(buf)) str += String.fromCharCode(b);
  return btoa(str).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function base64urlToBuf(str) {
  const b64 = str.replace(/-/g, '+').replace(/_/g, '/').padEnd(str.length + ((4 - (str.length % 4)) % 4), '=');
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes.buffer;
}

// Whether this device has a platform authenticator (Face ID / Touch ID /
// fingerprint / Windows Hello) available at all -- checked before showing
// the "set up" option, since WebAuthn itself may exist without one.
export async function isAppLockAvailable() {
  if (!window.PublicKeyCredential?.isUserVerifyingPlatformAuthenticatorAvailable) return false;
  try {
    return await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
  } catch {
    return false;
  }
}

// Creates a new platform passkey and returns its credential ID (base64url)
// for the caller to store. Throws if the user cancels or verification fails.
export async function enrollAppLock() {
  const credential = await navigator.credentials.create({
    publicKey: {
      challenge: randomBytes(32),
      rp: { name: RP_NAME, id: location.hostname },
      user: { id: randomBytes(16), name: 'life-os-owner', displayName: 'Life OS' },
      pubKeyCredParams: [
        { type: 'public-key', alg: -7 },   // ES256
        { type: 'public-key', alg: -257 }, // RS256
      ],
      authenticatorSelection: { authenticatorAttachment: 'platform', userVerification: 'required' },
      timeout: 60000,
    },
  });
  if (!credential) throw new Error('No credential was created.');
  return bufToBase64url(credential.rawId);
}

// Prompts for the platform authenticator against a previously-enrolled
// credential ID. Resolves true on success; throws (NotAllowedError etc.) on
// cancel/failure -- callers should catch and treat as "stay locked."
export async function verifyAppLock(credentialId) {
  const assertion = await navigator.credentials.get({
    publicKey: {
      challenge: randomBytes(32),
      allowCredentials: [{ id: base64urlToBuf(credentialId), type: 'public-key' }],
      userVerification: 'required',
      timeout: 60000,
    },
  });
  return !!assertion;
}
